import React, { useState } from 'react';
import { useStripe, useElements, CardElement } from '@stripe/react-stripe-js';
import './payment.css';

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3000";

const CheckoutForm = ({ bookingId, amount, onPaymentSuccess }) => {
  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
  
    if (!stripe || !elements) {
      return;
    }
  
    const cardElement = elements.getElement(CardElement);
  
    const { error, paymentMethod } = await stripe.createPaymentMethod({
      type: 'card',
      card: cardElement,
    });
  
    if (error) {
      setError(error.message);
      return;
    }
  
    const response = await fetch(`${API_URL}/payments`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        stripeToken: paymentMethod.id,
        booking_id: bookingId, // Ensure this is correctly set to the booking ID
        amount: amount, // Amount in dollars
      }),
    });
  
    if (!response.ok) {
      const paymentError = await response.json();
      setError(paymentError.error);
    } else {
      const paymentResult = await response.json();
      onPaymentSuccess(paymentResult);
    }
  };  

  return (
    <form className="payment-form" onSubmit={handleSubmit}>
      <h2>Complete Your Payment</h2>
      <CardElement className="StripeElement" />
      <button type="submit" disabled={!stripe || loading}>
        {loading ? 'Processing...' : 'Pay Now'}
      </button>
      {error && <div className="error-message">{error}</div>}
    </form>
  );
};

export default CheckoutForm;
